// Determine season from current month and pick a rotating topic
const now = new Date();
const monthNum = now.getMonth();
const dayOfYear = Math.floor((now - new Date(now.getFullYear(), 0, 0)) / 86400000);

// Season mapping
let season;
if (monthNum >= 2 && monthNum <= 4) season = 'Spring';
else if (monthNum >= 5 && monthNum <= 7) season = 'Summer';
else if (monthNum >= 8 && monthNum <= 10) season = 'Fall';
else season = 'Winter';

// Topic pools by season
const topicPools = {
  Spring: [
    'Spring lawn prep tips for Madison homeowners',
    'Pre-emergent weed control timing in southern Wisconsin',
    'How to repair winter damage on your Madison lawn',
    'Spring fertilizer application schedule',
    'Aeration benefits for compacted Madison clay soil',
    'Overseeding bare spots after winter',
    'Crabgrass prevention window in Madison',
    'Spring cleanup checklist for your yard',
    'Grub damage prevention starts now',
    'Mowing height tips for spring growth'
  ],
  Summer: [
    'Watering schedule for Madison lawns in summer heat',
    'How to keep your lawn green during drought',
    'Summer weed control without burning your grass',
    'Mosquito and tick prevention for Madison yards',
    'Why your lawn turns brown in July and what to do',
    'Proper mowing height during summer stress',
    'Fungus prevention in humid Madison summers',
    'Summer fertilizer application tips',
    'Shade lawn care for areas under trees',
    'Japanese beetle control for Madison lawns'
  ],
  Fall: [
    'Fall is the best time to seed your Madison lawn',
    'Fall fertilizer — the most important application of the year',
    'Leaf removal vs mulching — what\'s better for your lawn',
    'Fall aeration and overseeding combo benefits',
    'Preparing your lawn for Madison winters',
    'When to stop mowing in fall',
    'Fall weed control for broadleaf weeds',
    'Winterizer fertilizer timing for Wisconsin',
    'Raking vs leaving leaves on your lawn',
    'Fall grub treatment window'
  ],
  Winter: [
    'Winter lawn care tips for Madison homeowners',
    'Planning your spring lawn care schedule now',
    'Why salt damage hurts your lawn and how to prevent it',
    'Winter is the best time to book spring services',
    'Snow mold prevention and treatment',
    'Off-season soil testing for better spring results',
    'Winter watering — does your lawn need it?',
    'Equipment maintenance tips for the off-season',
    'Understanding your soil type in Madison',
    'Early booking discounts for spring lawn care'
  ]
};

const topics = topicPools[season];

// Rotate through topics using day-of-year to avoid repeats within 30 days
// Each MWF post gets a different index based on the post number this year
const mwfCount = Math.floor(dayOfYear / 2); // approximate MWF post number
const topicIndex = mwfCount % topics.length;
const topic = topics[topicIndex];

// Generate a simple hash for dedup tracking
const topicHash = topic.replace(/[^a-zA-Z0-9]/g, '').substring(0, 20).toLowerCase();

return [{
  json: {
    season,
    topic,
    topicHash,
    month: now.toLocaleString('en-US', { month: 'long' }),
    year: now.getFullYear(),
    dayOfYear,
    generatedAt: now.toISOString()
  }
}];

