// Parse Claude API response and prepare for storage
const response = $input.first().json;
const prevData = $('Determine Season & Topic').first().json;

// Extract text from Claude response
let postText = '';
if (response.content && response.content[0] && response.content[0].text) {
  postText = response.content[0].text.trim();
}

// Strip any quotes if Claude wrapped the response
postText = postText.replace(/^"|"$/g, '').trim();

// Truncate to 300 chars if needed, breaking at last complete sentence or word
if (postText.length > 300) {
  let truncated = postText.substring(0, 297);
  // Try to break at last sentence
  const lastPeriod = truncated.lastIndexOf('.');
  const lastExclaim = truncated.lastIndexOf('!');
  const lastBreak = Math.max(lastPeriod, lastExclaim);
  if (lastBreak > 200) {
    truncated = truncated.substring(0, lastBreak + 1);
  } else {
    // Break at last space
    const lastSpace = truncated.lastIndexOf(' ');
    truncated = truncated.substring(0, lastSpace) + '...';
  }
  postText = truncated;
}

// Generate image prompt suggestion based on topic
const imagePrompt = `Professional lawn care photo: ${prevData.topic}. Madison Wisconsin, ${prevData.season.toLowerCase()} season, lush green grass, residential neighborhood. Clean, bright, inviting.`;

return [{
  json: {
    post_content: postText,
    char_count: postText.length,
    image_prompt: imagePrompt,
    season: prevData.season,
    topic: prevData.topic,
    topic_hash: prevData.topicHash,
    generated_at: prevData.generatedAt
  }
}];

